        assert caplog.messages == ['DР В РЎвЂєР вЂ™Р’Вµbug\tMР В РІР‚СњР Р†Р вЂљРІР‚СњssР В РІР‚СљР В РІвЂљВ¬ge', 'FР В РЎвЂєР вЂ™Р’В±tal\tР В РІР‚СљР Р†РІР‚С™Р’В¬rrР В РІР‚СћР В Р Р‰r']
